mapper.select:
select id, record_date, meal_type, total_count, success_count, fail_count, status, generate_time,
       create_by, update_by, deleted, create_time, update_time
from meal_plan

    deleted = 0

        and record_date = #{criteria.recordDate}


        and meal_type = #{criteria.mealType}


        and status = #{criteria.status}


order by generate_time desc

select id, record_date, meal_type, total_count, success_count, fail_count, status, generate_time, create_by, update_by, deleted, create_time, update_time from meal_plan where id in
#{id}
and deleted = 0

mapper.update:
update meal_plan
set deleted = 1
where record_date = #{recordDate}
  and meal_type = #{mealType}
  and deleted = 0

update meal_plan set deleted = 1 where id in
#{id}
and deleted = 0

